let quill_delta = require('quill-delta');

describe('test quill_delta', function() {
    it('test quill-delta.OpIterator constructor', function(done) {
        const ops = [
            { insert: 'Hello' },
            { retain: 5 },
            { delete: 3 }
        ];
        const iterator = new quill_delta.OpIterator(ops);

        assert.strictEqual(iterator.ops, ops);
        assert.strictEqual(iterator.index, 0);
        assert.strictEqual(iterator.offset, 0);
        done();
    });

    it('test hasNext method', function(done) {
        const ops = [{ insert: 'Hello' }];
        const iterator = new quill_delta.OpIterator(ops);

        assert.strictEqual(iterator.hasNext(), true);

        // Move to end
        iterator.next();
        assert.strictEqual(iterator.hasNext(), false);

        // Empty ops
        const emptyIterator = new quill_delta.OpIterator([]);
        assert.strictEqual(emptyIterator.hasNext(), false);
        done();
    });

    it('test next method with insert operations', function(done) {
        const ops = [{ insert: 'Hello World' }];
        const iterator = new quill_delta.OpIterator(ops);

        // Get part of insert
        let result = iterator.next(5);
        assert.deepStrictEqual(result, { insert: 'Hello' });

        // Get remaining part
        result = iterator.next();
        assert.deepStrictEqual(result, { insert: ' World' });

        // Should return infinite retain when no more ops
        result = iterator.next();
        assert.deepStrictEqual(result, { retain: Infinity });
        done();
    });

    it('test next method with retain operations', function(done) {
        const ops = [{ retain: 10, attributes: { bold: true } }];
        const iterator = new quill_delta.OpIterator(ops);

        let result = iterator.next(5);
        assert.deepStrictEqual(result, { retain: 5, attributes: { bold: true } });

        result = iterator.next();
        assert.deepStrictEqual(result, { retain: 5, attributes: { bold: true } });
        done();
    });

    it('test next method with delete operations', function(done) {
        const ops = [{ delete: 7 }];
        const iterator = new quill_delta.OpIterator(ops);

        let result = iterator.next(3);
        assert.deepStrictEqual(result, { delete: 3 });

        result = iterator.next();
        assert.deepStrictEqual(result, { delete: 4 });
        done();
    });

    it('test peek and peekLength methods', function(done) {
        const ops = [
            { insert: 'Hello' },
            { retain: 5 }
        ];
        const iterator = new quill_delta.OpIterator(ops);

        assert.deepStrictEqual(iterator.peek(), { insert: 'Hello' });
        assert.strictEqual(iterator.peekLength(), 5);

        // Move partially through first op
        iterator.next(2);
        assert.deepStrictEqual(iterator.peek(), { insert: 'Hello' });
        assert.strictEqual(iterator.peekLength(), 3);

        // Move to next op
        iterator.next();
        assert.deepStrictEqual(iterator.peek(), { retain: 5 });
        assert.strictEqual(iterator.peekLength(), 5);

        // Move past all ops
        iterator.next();
        assert.strictEqual(iterator.peek(), undefined);
        assert.strictEqual(iterator.peekLength(), Infinity);
        done();
    });

    it('test peekType method', function(done) {
        const deleteOps = [{ delete: 5 }];
        const retainOps = [{ retain: 5 }];
        const insertOps = [{ insert: 'Hello' }];
        const emptyOps = [];

        assert.strictEqual(new quill_delta.OpIterator(deleteOps).peekType(), 'delete');
        assert.strictEqual(new quill_delta.OpIterator(retainOps).peekType(), 'retain');
        assert.strictEqual(new quill_delta.OpIterator(insertOps).peekType(), 'insert');
        assert.strictEqual(new quill_delta.OpIterator(emptyOps).peekType(), 'retain');
        done();
    });

    it('test rest method', function(done) {
        const ops = [
            { insert: 'Hello' },
            { retain: 5 },
            { delete: 3 }
        ];
        const iterator = new quill_delta.OpIterator(ops);

        // At beginning
        let rest = iterator.rest();
        assert.deepStrictEqual(rest, ops);

        // After consuming one op
        iterator.next();
        rest = iterator.rest();
        assert.deepStrictEqual(rest, [{ retain: 5 }, { delete: 3 }]);

        // After partial consumption
        iterator.index = 0;
        iterator.offset = 0;
        iterator.next(2); // Consume part of first op
        rest = iterator.rest();
        assert.deepStrictEqual(rest, [
            { insert: 'llo' },
            { retain: 5 },
            { delete: 3 }
        ]);

        // When no more ops
        iterator.next(); // consume rest of ops
        iterator.next();
        iterator.next();
        rest = iterator.rest();
        assert.deepStrictEqual(rest, []);
        done();
    });

    it('test complex iteration scenario', function(done) {
        const ops = [
            { insert: 'Hello' },
            { retain: 3, attributes: { bold: true } },
            { delete: 2 },
            { insert: ' World' }
        ];
        const iterator = new quill_delta.OpIterator(ops);

        const results = [];
        while (iterator.hasNext()) {
            results.push(iterator.next(2));
        }

        assert.deepStrictEqual(results, [
            { insert: 'He' },
            { insert: 'llo' },
            { retain: 2, attributes: { bold: true } },
            { retain: 1, attributes: { bold: true } },
            { delete: 2 },
            { insert: ' W' },
            { insert: 'orld' }
        ]);
        done();
    });
});
